    }
    if (!output_itemsets_d) {
        printf("ERROR: clCreateBuffer output_item_set (size:%d) => %d\n", max_cols * max_rows, -1);
        free(source);
        free(input_itemsets_d);
        free(reference_d);
        return -1;
    }

#ifdef TIMING
