        }
    }

    printf("Processing lower-right matrix\n");
    for (int blk = worksize / BLOCK_SIZE - 1; blk >= 1; blk--) {
#pragma omp parallel for schedule(static)
        for (int bx = 0; bx < blk; bx++) {
            int b_index_x = bx + block_width - blk;
            int b_index_y = block_width - bx - 1;
            process_tile(reference_d, input_itemsets_d, max_cols, penalty,
                         b_index_y, b_index_x, offset_r, offset_c);
        }
    }

#ifdef TIMING
