        if (i > 0 && j > 0) {
            nw = output_itemsets[(i - 1) * max_cols + j - 1];
            w = output_itemsets[i * max_cols + j - 1];
            n = output_itemsets[(i - 1) * max_cols + j];
        } else if (i == 0) {
            nw = n = LIMIT;
            w = output_itemsets[i * max_cols + j - 1];
        } else if (j == 0) {
            nw = w = LIMIT;
            n = output_itemsets[(i - 1) * max_cols + j];
        } else {
        }

        int new_nw, new_w, new_n;
        new_nw = nw + reference[i * max_cols + j];
        new_w = w - penalty;
        new_n = n - penalty;

        traceback = maximum(new_nw, new_w, new_n);
        if (traceback == new_nw)
            traceback = nw;
        if (traceback == new_w)
            traceback = w;
        if (traceback == new_n)
            traceback = n;

        fprintf(fpo, "%d ", traceback);

        if (traceback == nw) {
            i--;
            j--;
            continue;
        } else if (traceback == w) {
            j--;
            continue;
        } else if (traceback == n) {
            i--;
            continue;
        } else
            ;
    }

    fclose(fpo);
#endif

#ifdef TIMING
    gettimeofday(&tv_close_start, NULL);
#endif

    printf("Computation Done\n");

    if (shutdown()) {
        free(source);
        free(input_itemsets_d);
        free(output_itemsets_d);
        free(reference_d);
        free(reference);
        free(input_itemsets);
        free(output_itemsets);
        return -1;
    }

    free(input_itemsets_d);
    free(output_itemsets_d);
    free(reference_d);

#ifdef TIMING
    gettimeofday(&tv_close_end, NULL);
    tvsub(&tv_close_end, &tv_close_start, &tv);
    close_time = tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
    tvsub(&tv_close_end, &tv_total_start, &tv);
    total_time = tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;

    printf("Init: %f\n", init_time);
